mapper.select:
select YYYYMM,SEL_CODE, DW_SITE as DW_SITE_ORG, CASE WHEN DW_SITE='HQ' then '본사' WHEN DW_SITE='VN' then 'VINA' end as DW_SITE, 구분,구분_ord,도우코드,MODEL_N_TYPE,도우모델,작업구분,org작업구분,model,Inch,Site,BOH_MONTH,IN_MONTH,BONUS_MONTH,EOH_MONTH,OUT_MONTH,LOSS_MONTH,NG_MONTH,수율제외_MONTH,REWORK진행_MONTH,SHIPPING_PLAN_MONTH,SHIPPING_ACTUAL_MONTH,material_loss from DOI_PROD_SUBUL where 1=1
and yyyymm = #{yyyymm}
and DW_SITE = #{site}
order BY 도우코드,MODEL_N_TYPE,도우모델,구분_ord;

select YYYYMM,SEL_CODE, DW_SITE as DW_SITE_ORG, CASE WHEN DW_SITE='HQ' then '본사' WHEN DW_SITE='VN' then 'VINA' end as DW_SITE, 구분,구분_ord,도우코드,MODEL_N_TYPE,도우모델,작업구분,org작업구분,model,Inch,Site,BOH_MONTH,IN_MONTH,BONUS_MONTH,EOH_MONTH,OUT_MONTH,LOSS_MONTH,NG_MONTH,수율제외_MONTH,REWORK진행_MONTH,SHIPPING_PLAN_MONTH,SHIPPING_ACTUAL_MONTH,material_loss from DOI_RND_SUBUL where 1=1
and yyyymm = #{yyyymm}
and DW_SITE = #{site}
order BY 도우코드,MODEL_N_TYPE,도우모델,구분_ord;

