INSERT INTO DOI_PROD_SUBUL (YYYYMM, SEL_CODE, site, GUBUN, GUBUN_ORD, DW_CODE, MODEL_N_TYPE, DW_MODEL, WORK_GUBUN, ORG_WORK_GUBUN, MODEL, INCH, OUT_SITE, BOH_MONTH, IN_MONTH, BONUS_MONTH, EOH_MONTH, OUT_MONTH, LOSS_MONTH, NG_MONTH, EXCEPT_MONTH, REWORK_MONTH, SHIPPING_PLAN_MONTH, SHIPPING_ACTUAL_MONTH, MATERIAL_LOSS)
SELECT YYYYMM, SEL_CODE, site, GUBUN, GUBUN_ORD, DW_CODE, MODEL_N_TYPE, DW_MODEL, WORK_GUBUN, ORG_WORK_GUBUN, MODEL, INCH, OUT_SITE, BOH_MONTH, IN_MONTH, BONUS_MONTH, EOH_MONTH, OUT_MONTH, LOSS_MONTH, NG_MONTH, EXCEPT_MONTH, REWORK_MONTH, SHIPPING_PLAN_MONTH, SHIPPING_ACTUAL_MONTH, MATERIAL_LOSS
FROM (
	SELECT *, MAX(seq_no) over (partition by YYYYMM, SITE, MODEL) max_seq_no FROM #TempTable
) A
WHERE 1=1
AND seq_no = max_seq_no
AND NOT EXISTS (
	SELECT 1
	FROM DOI_PROD_SUBUL b
	WHERE 1=1
	AND b.YYYYMM = a.YYYYMM
	AND b.site = a.site
	AND b.DW_MODEL = a.DW_MODEL
);

DROP TABLE #TempTable;

INSERT INTO DOI_PROD_SUBUL
(
	YYYYMM,
	SEL_CODE,
	구분 AS GUBUN,
	구분_ord AS GUBUN_ORD,
	도우코드 AS DW_CODE,
	MODEL_N_TYPE,
	도우모델 AS DW_MODEL,
	작업구분 AS WORK_GUBUN,
	org작업구분 AS ORG_WORK_GUBUN,
	MODEL, 
	INCH,
	SITE AS OUT_SITE,
	BOH_MONTH,
	IN_MONTH,
	BONUS_MONTH,
	EOH_MONTH,
	OUT_MONTH,
	LOSS_MONTH,
	NG_MONTH,
	수율제외_MONTH AS EXCEPT_MONTH,
	REWORK진행_MONTH AS REWORK_MONTH,
	SHIPPING_PLAN_MONTH,
	SHIPPING_ACTUAL_MONTH,
	MATERIAL_LOSS
)
VALUES
(
#{yyyymm}
, #{selCode}
, CASE WHEN #{dwSite}='본사' Then 'HQ'  WHEN #{dwSite}='베트남' then 'VN' else left(#{dwSite},2) end
, #{gubun}
, #{gubunOrd}
, #{dwCode}
, #{modelNType}
, #{dwModel}
, #{workGubun}
, #{orgWorkGubun}
, #{model}
, #{inch}
, #{outSite}
, #{bohMonth}
, #{inMonth}
, #{bonusMonth}
, #{eohMonth}
, #{outMonth}
, #{lossMonth}
, #{ngMonth}
, #{exceptMonth}
, #{reworkMonth}
, #{shippingPlanMonth}
, #{shippingActualMonth}
, #{materialLoss}
);

