,작업구분 = #{workGubun}
,org작업구분 = #{orgWorkGubun}
,INCH = #{inch}
,OUT_SITE = #{outSite}
,BOH_MONTH = #{bohMonth}
,IN_MONTH = #{inMonth}
,BONUS_MONTH = #{bonusMonth}
,EOH_MONTH = #{eohMonth}
,OUT_MONTH = #{outMonth}
